#include "my_stdlib.h"
extern int main();
void _start() {
int exit_code = main();
long exit_syscall = 60;
__asm__ volatile(
"syscall"
:
: "a" (exit_syscall), "D" (exit_code)
: "rcx", "r11", "memory"
);
while(1);
}


