#!/usr/bin/env node
// MIPS32r2 (o32, little-endian) interpreter for doomgeneric_mips.
// Handles the custom syscall ABI used by my_stdlib.c / start.c:
//   syscall number in $v0, args in $a0-$a3,$t0,$t1, return in $v0.
//   syscall numbers: read=0 write=1 open=2 close=3 lseek=8 nanosleep=35
//     exit=60 fsync=74 rename=82 mkdir=83 unlink=87 gettimeofday=96 time=201
// Errors are returned as negative errno in $v0 (guest sets errno = -ret).

'use strict';
const fs = require('fs');

const ELF = fs.readFileSync(process.argv[2] || '/app/doomgeneric_mips');

// ---- Parse ELF32 little-endian, load PT_LOAD segments ----
function u16(o){ return ELF[o] | (ELF[o+1]<<8); }
function u32(o){ return (ELF[o] | (ELF[o+1]<<8) | (ELF[o+2]<<16) | (ELF[o+3]<<24))>>>0; }

if (!(ELF[0]===0x7f && ELF[1]===0x45 && ELF[2]===0x4c && ELF[3]===0x46))
  throw new Error('not an ELF file');
const entry = u32(24);
const phoff = u32(28);
const phentsize = u16(42);
const phnum = u16(44);

const segs = [];
let maxAddr = 0, minAddr = 0xffffffff;
for (let i=0;i<phnum;i++){
  const o = phoff + i*phentsize;
  const type = u32(o);
  if (type !== 1) continue; // PT_LOAD
  const off = u32(o+4), vaddr = u32(o+8), filesz = u32(o+16), memsz = u32(o+20);
  segs.push({off,vaddr,filesz,memsz});
  if (vaddr < minAddr) minAddr = vaddr;
  if (vaddr + memsz > maxAddr) maxAddr = vaddr + memsz;
}

const BASE = minAddr & ~0xffff;             // 0x400000
const STACK_SIZE = 0x1000000;               // 16 MB stack
let memTop = ((maxAddr + 0xffff) & ~0xffff) + STACK_SIZE;
const SIZE = memTop - BASE;

const ab = new ArrayBuffer(SIZE);           // zero-initialised (handles .bss)
const u8  = new Uint8Array(ab);
const i8  = new Int8Array(ab);
const u16m = new Uint16Array(ab);
const i16m = new Int16Array(ab);
const u32m = new Uint32Array(ab);
const i32m = new Int32Array(ab);
const dv  = new DataView(ab);

for (const s of segs){
  for (let k=0;k<s.filesz;k++) u8[(s.vaddr - BASE) + k] = ELF[s.off + k];
}

// ---- CPU state ----
const gpr = new Int32Array(32);
let hi = 0, lo = 0;
let pc = entry, npc = (entry + 4)>>>0;

// initial stack pointer (8/16-byte aligned), gp = reginfo gp_value
gpr[29] = (memTop - 32) & ~0xf;   // $sp
gpr[28] = 0x0047d090;             // $gp (ri_gp_value)
gpr[31] = 0;                      // $ra

// FPU: 32 x 32-bit registers, one condition flag (FCC0)
const fbuf = new ArrayBuffer(32*4);
const ff = new DataView(fbuf);
let fcc = false;
const getF32 = (i)=>ff.getFloat32(i*4,true);
const setF32 = (i,v)=>ff.setFloat32(i*4,v,true);
const getF64 = (i)=>ff.getFloat64(i*4,true);
const setF64 = (i,v)=>ff.setFloat64(i*4,v,true);
const getFU  = (i)=>ff.getUint32(i*4,true);
const setFU  = (i,v)=>ff.setUint32(i*4,v>>>0,true);
const getFI  = (i)=>ff.getInt32(i*4,true);

// ---- 64-bit multiply helpers ----
function umulHi(x,y){
  const xl=x&0xffff, xh=x>>>16, yl=y&0xffff, yh=y>>>16;
  const ll=xl*yl, lh=xl*yh, hl=xh*yl, hh=xh*yh;
  const cross=(ll>>>16)+(lh&0xffff)+(hl&0xffff);
  return (hh + (lh>>>16) + (hl>>>16) + (cross>>>16))>>>0;
}

// ---- syscall / file handling ----
const pos = new Map();     // fd -> current offset (for real files)
const paths = new Map();   // fd -> path (to detect frame writes)
let framesSaved = 0;
const MAX_FRAMES = parseInt(process.env.DOOM_MAX_FRAMES || '1', 10);
const FRAME_PATH = process.env.DOOM_FRAME_PATH || '/tmp/frame.bmp';

function readCString(addr){
  let s = '';
  let p = addr - BASE;
  while (u8[p] !== 0){ s += String.fromCharCode(u8[p]); p++; }
  return s;
}

function doSyscall(){
  const num = gpr[2];
  const a0 = gpr[4], a1 = gpr[5], a2 = gpr[6], a3 = gpr[7];
  try {
    switch (num){
      case 0: { // read(fd, buf, count)
        const fd=a0, buf=a1, count=a2>>>0;
        if (count===0) return 0;
        const b = Buffer.from(ab, buf - BASE, count);
        const p = pos.get(fd);
        const n = fs.readSync(fd, b, 0, count, (p===undefined)?null:p);
        if (p!==undefined) pos.set(fd, p + n);
        return n;
      }
      case 1: { // write(fd, buf, count)
        const fd=a0, buf=a1, count=a2>>>0;
        if (count===0) return 0;
        const b = Buffer.from(ab, buf - BASE, count);
        let n;
        if (fd===1 || fd===2) n = fs.writeSync(fd, b, 0, count);
        else {
          const p = pos.get(fd);
          n = fs.writeSync(fd, b, 0, count, (p===undefined)?null:p);
          if (p!==undefined) pos.set(fd, p + n);
        }
        return n;
      }
      case 2: { // open(path, flags, mode)
        const path = readCString(a0);
        const flags = a1|0;
        const mode = a2 ? (a2>>>0) : 0o666;
        const fd = fs.openSync(path, flags, mode);
        // initial position: end for O_APPEND(1024), else 0
        pos.set(fd, (flags & 1024) ? fs.fstatSync(fd).size : 0);
        paths.set(fd, path);
        return fd;
      }
      case 3: { // close(fd)
        const fd=a0;
        const path = paths.get(fd);
        fs.closeSync(fd);
        pos.delete(fd); paths.delete(fd);
        if (path === FRAME_PATH){
          framesSaved++;
          process.stderr.write(`[vm] frame ${framesSaved} saved to ${path}\n`);
          if (framesSaved >= MAX_FRAMES){ process.exit(0); }
        }
        return 0;
      }
      case 8: { // lseek(fd, offset, whence)
        const fd=a0; const offset=a1|0; const whence=a2|0;
        let base;
        if (whence===0) base=0;
        else if (whence===1) base=(pos.get(fd)||0);
        else base=fs.fstatSync(fd).size;
        const np = base + offset;
        pos.set(fd, np);
        return np;
      }
      case 35: return 0; // nanosleep
      case 60: process.exit(a0|0); // exit
      case 74: { const fd=a0; try{ fs.fsyncSync(fd);}catch(e){} return 0; } // fsync
      case 82: { fs.renameSync(readCString(a0), readCString(a1)); return 0; } // rename
      case 83: { // mkdir
        try { fs.mkdirSync(readCString(a0), a1?(a1>>>0):0o777); }
        catch(e){ if (e.code==='EEXIST') return -17; throw e; }
        return 0;
      }
      case 87: { fs.unlinkSync(readCString(a0)); return 0; } // unlink
      case 96: { // gettimeofday(tv, tz)
        if (a0){ const now=Date.now(); const p=a0-BASE;
          dv.setInt32(p,   Math.floor(now/1000), true);
          dv.setInt32(p+4, (now%1000)*1000, true); }
        return 0;
      }
      case 201: { // time(tloc)
        const t = Math.floor(Date.now()/1000);
        if (a0) dv.setInt32(a0-BASE, t, true);
        return t;
      }
      default:
        process.stderr.write(`[vm] unimplemented syscall ${num}\n`);
        return -38; // -ENOSYS
    }
  } catch(e){
    const errnoMap={EPERM:1,ENOENT:2,EBADF:9,EACCES:13,EEXIST:17,ENOTDIR:20,EISDIR:21,EINVAL:22,EMFILE:24,ENOSPC:28};
    return -(errnoMap[e.code] || 22);
  }
}

// ---- main interpreter loop ----
const B = BASE;
function run(){
  for(;;){
    const cpc = pc;
    const inst = u32m[(cpc - B) >>> 2];
    pc = npc;
    npc = (pc + 4) >>> 0;

    const op = inst >>> 26;
    const rs = (inst >>> 21) & 31;
    const rt = (inst >>> 16) & 31;
    const rd = (inst >>> 11) & 31;
    const sa = (inst >>> 6) & 31;
    const funct = inst & 63;
    const imm = (inst << 16) >> 16;      // sign-extended
    const uimm = inst & 0xffff;

