        u32m[p>>>2] = getFU(rt); u32m[(p+4)>>>2] = getFU(rt+1); break; }
      default: unimpl(inst, cpc);
    }
    gpr[0] = 0;
  }
}

function addAcc(ph, pl){
  const nlo = (lo >>> 0) + (pl >>> 0);
  lo = nlo | 0;
  hi = (hi + ph + (nlo >= 0x100000000 ? 1 : 0)) | 0;
}

function cop1(inst, cpc){
  const rs = (inst >>> 21) & 31;   // format / sub-op
  const rt = (inst >>> 16) & 31;
  const fs = (inst >>> 11) & 31;
  const fd = (inst >>> 6) & 31;
  const funct = inst & 63;
  switch (rs){
    case 0x00: gpr[rt] = getFI(fs); return;            // mfc1
    case 0x02: gpr[rt] = getFI(fs); return;            // cfc1 (approx)
    case 0x03: gpr[rt] = getFI(fs+1); return;          // mfhc1
    case 0x04: setFU(fs, gpr[rt]); return;             // mtc1
    case 0x06: return;                                 // ctc1 (ignore)
    case 0x07: setFU(fs+1, gpr[rt]); return;           // mthc1
    case 0x08: { // BC1
      const tf = (rt & 1) === 1;
      if (fcc === tf) npc = (cpc + 4 + (((inst<<16)>>16) << 2)) >>> 0;
      return;
    }
    case 0x10: { // single
      switch (funct){
        case 0x00: setF32(fd, getF32(fs) + getF32(inst>>>16 & 31 ? (inst>>>16)&31 : 0)); return;
      }
      return cop1FmtS(inst, funct, fs, fd, (inst>>>16)&31, cpc);
    }
    case 0x11: return cop1FmtD(inst, funct, fs, fd, (inst>>>16)&31, cpc);
    case 0x14: { // word -> convert
      if (funct === 0x20) { setF32(fd, getFI(fs)); return; }        // cvt.s.w
      if (funct === 0x21) { setF64(fd, getFI(fs)); return; }        // cvt.d.w
      unimpl(inst, cpc); return;
    }
    default: unimpl(inst, cpc);
  }
}

function cop1FmtS(inst, funct, fs, fd, ftr, cpc){
  switch (funct){
    case 0x00: setF32(fd, getF32(fs) + getF32(ftr)); return; // add.s
    case 0x01: setF32(fd, getF32(fs) - getF32(ftr)); return; // sub.s
    case 0x02: setF32(fd, getF32(fs) * getF32(ftr)); return; // mul.s
    case 0x03: setF32(fd, getF32(fs) / getF32(ftr)); return; // div.s
    case 0x04: setF32(fd, Math.sqrt(getF32(fs))); return;    // sqrt.s
    case 0x05: setF32(fd, Math.abs(getF32(fs))); return;     // abs.s
    case 0x06: setFU(fd, getFU(fs)); return;                 // mov.s
    case 0x07: setF32(fd, -getF32(fs)); return;              // neg.s
    case 0x0d: setFU(fd, Math.trunc(getF32(fs))|0); return;  // trunc.w.s
    case 0x11: if (fcc === ((ftr & 1)===1)) setFU(fd, getFU(fs)); return; // movt/movf.s
    case 0x21: setF64(fd, getF32(fs)); return;               // cvt.d.s
    case 0x24: setFU(fd, Math.trunc(getF32(fs))|0); return;  // cvt.w.s (trunc-ish)
    default:
      if (funct >= 0x30){ fpCompare(funct & 0xf, getF32(fs), getF32(ftr)); return; }
      unimpl(inst, cpc);
  }
}

function cop1FmtD(inst, funct, fs, fd, ftr, cpc){
  switch (funct){
    case 0x00: setF64(fd, getF64(fs) + getF64(ftr)); return; // add.d
    case 0x01: setF64(fd, getF64(fs) - getF64(ftr)); return; // sub.d
    case 0x02: setF64(fd, getF64(fs) * getF64(ftr)); return; // mul.d
    case 0x03: setF64(fd, getF64(fs) / getF64(ftr)); return; // div.d
    case 0x04: setF64(fd, Math.sqrt(getF64(fs))); return;    // sqrt.d
    case 0x05: setF64(fd, Math.abs(getF64(fs))); return;     // abs.d
    case 0x06: setFU(fd, getFU(fs)); setFU(fd+1, getFU(fs+1)); return; // mov.d
    case 0x07: setF64(fd, -getF64(fs)); return;              // neg.d
    case 0x0d: setFU(fd, Math.trunc(getF64(fs))|0); return;  // trunc.w.d
    case 0x11: if (fcc === ((ftr & 1)===1)){ setFU(fd, getFU(fs)); setFU(fd+1, getFU(fs+1)); } return; // movt/movf.d
    case 0x20: setF32(fd, getF64(fs)); return;               // cvt.s.d
    case 0x24: setFU(fd, Math.trunc(getF64(fs))|0); return;  // cvt.w.d
    default:
      if (funct >= 0x30){ fpCompare(funct & 0xf, getF64(fs), getF64(ftr)); return; }
      unimpl(inst, cpc);
  }
}

function fpCompare(cond, a, b){
  const un = (a!==a) || (b!==b);
  const less = !un && a < b;
  const eq = !un && a === b;
  fcc = (!!(cond&1) && un) || (!!(cond&2) && eq) || (!!(cond&4) && less);
}

function unimpl(inst, cpc){
  process.stderr.write(`[vm] unimplemented instruction 0x${(inst>>>0).toString(16)} at 0x${cpc.toString(16)}\n`);
  process.exit(1);
}

